private struct FacebookGenericListScreen: View {
    let title: String
    var body: some View {
        NavigationStack {
            List(0..<8, id: \.self) { i in
                HStack {
                    RoundedRectangle(cornerRadius: 8).fill(FacebookTokens.fbBlue.opacity(0.15)).frame(width: 44, height: 44)
                    VStack(alignment: .leading) {
                        Text("\(title) \(i + 1)").font(.system(size: 17, weight: .semibold))
                        Text("Mis à jour récemment").font(.system(size: 14)).foregroundStyle(.secondary)
                    }
                }
            }
            .navigationTitle(title)
        }
    }
}

